/*****************************************************************
* PROJECT: NOP 2026-27 National Risk Model Deployment           *
* AUTHOR:  Jason Hao (Technical Lead)                           *
* REF:     Decision Memo 2026-06-17; Scenario B (15% Weight)    *
*****************************************************************/

LIBNAME HQ_DATA "/data/tdg/oversight/production";

/* STEP 1: LOAD RAW FACILITY UNIVERSE FROM CORE DATABASE */
PROC SQL;
CREATE TABLE WORK.RAW_UNIVERSE AS 
SELECT * FROM HQ_DATA.TDG_CORE_MASTER;

/* STEP 2: DATA HYGIENE - ADDRESSING LEGACY DECAY (MSG-008) */
/* Filtering records where FACILITY_AGE_DATE defaults to 01JAN1900 */
DATA WORK.CLEANED_UNIVERSE;
SET WORK.RAW_UNIVERSE;
IF FACILITY_AGE_DATE <= '01JAN1901'd THEN DO;
OUTPUT_FLAG = 'DELETED_LEGACY_DECAY';
DELETE;
END;
ELSE OUTPUT_FLAG = 'VALID_RECORD';
RUN;

/* STEP 3: APPLY SCENARIO B WEIGHTING PARAMETERS (15% GEO SENSITIVITY) */
%LET GEO_WT = 0.15;
%LET VOL_WT = 0.35;
%LET COMP_WT = 0.50;

DATA WORK.FINAL_RISK_SCORES;
SET WORK.CLEANED_UNIVERSE;

/* Calculate Urban Sensitivity Score */
IF DISTANCE_TO_CMA <= 50 THEN GEO_SCORE = 100 * &GEO_WT;
ELSE GEO_SCORE = 20 * &GEO_WT;

/* Final Weighted Score Aggregation */
FINAL_SCORE = (GEO_SCORE) + (VOLUME_RANK * &VOL_WT) + (COMPLIANCE_RANK * &COMP_WT);

/* APPLY STREAMLINING FILTER STRL-2026 */
IF YRS_SINCE_LAST_VIOLATION >= 5 AND FINAL_SCORE < 20 THEN DO;
INSPECTION_PRIORITY = 'LOW - STREAMLINED';
STRL_FLAG = 1;
END;
ELSE DO;
INSPECTION_PRIORITY = 'HIGH/STANDARD';
STRL_FLAG = 0;
END;
RUN;

/* STEP 4: PRODUCTION EXPORT */
PROC COPY IN=WORK OUT=HQ_DATA;
SELECT FINAL_RISK_SCORES;
RUN;
